    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //    {
        //       "symbol":"BTC-PERP",
        //       "instrument_id":"114jqr89-0-0",
        //       "instrument_uuid":"b3469e0b-222c-4f8a-9f68-1f9e44d7e5e0",
        //       "vwap":"52482.3",
        //       "net_size":"0",
        //       "buy_order_size":"0.001",
        //       "sell_order_size":"0",
        //       "im_contribution":"0.2",
        //       "unrealized_pnl":"0",
        //       "mark_price":"52406.8",
        //       "entry_vwap":"52472.9"
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "symbol");
        Object quantity = this.safeString(position, "net_size");
        market = this.safeMarket(marketId, market, "-");
        Object side = "long";
        if (Helpers.isTrue(Precise.stringLe(quantity, "0")))
        {
            side = "short";
            quantity = Precise.stringMul("-1", quantity);
        }
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalQuantity = quantity;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", CoinbaseinternationalCore.this.safeString(position, "id") );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "entryPrice", null );
            put( "markPrice", CoinbaseinternationalCore.this.safeNumber(position, "mark_price") );
            put( "notional", null );
            put( "collateral", null );
            put( "unrealizedPnl", CoinbaseinternationalCore.this.safeNumber(position, "unrealized_pnl") );
            put( "side", finalSide );
            put( "contracts", CoinbaseinternationalCore.this.parseNumber(finalQuantity) );
            put( "contractSize", CoinbaseinternationalCore.this.safeNumber(finalMarket, "contractSize") );
            put( "timestamp", null );
            put( "datetime", null );
            put( "hedged", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "initialMargin", CoinbaseinternationalCore.this.safeNumber(position, "im_contribution") );
            put( "initialMarginPercentage", null );
            put( "leverage", null );
            put( "liquidationPrice", null );
            put( "marginRatio", null );
            put( "marginMode", null );
            put( "percentage", null );
        }});
    }

